contracts/AccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

contract AccessControl {
    struct AccessGrant {
        string datasetId;
        string subjectDid;
        string purpose;
        uint64 expiresAt;
        bool active;
    }

    mapping(bytes32 => AccessGrant) private grants;

    event AccessGranted(
        bytes32 indexed grantId,
        string datasetId,
        string subjectDid,
        string purpose,
        uint64 expiresAt
    );

    event AccessRevoked(bytes32 indexed grantId, string datasetId, string subjectDid);

    function grantAccess(
        string calldata datasetId,
        string calldata subjectDid,
        string calldata purpose,
        uint64 expiresAt
    ) external returns (bytes32) {
        bytes32 grantId = keccak256(abi.encode(datasetId, subjectDid, purpose, expiresAt));
        grants[grantId] = AccessGrant({
            datasetId: datasetId,
            subjectDid: subjectDid,
            purpose: purpose,
            expiresAt: expiresAt,
            active: true
        });

        emit AccessGranted(grantId, datasetId, subjectDid, purpose, expiresAt);
        return grantId;
    }

    function revokeAccess(bytes32 grantId) external {
        AccessGrant storage grant = grants[grantId];
        require(grant.active, "grant inactive");
        grant.active = false;
        emit AccessRevoked(grantId, grant.datasetId, grant.subjectDid);
    }

    function getGrant(bytes32 grantId) external view returns (AccessGrant memory) {
        return grants[grantId];
    }
}

contracts/ContributionLedger.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

contract ContributionLedger {
    struct ContributionRecord {
        string trainingJobId;
        string participantDid;
        uint32 round;
        uint256 score;
        uint64 recordedAt;
    }

    mapping(bytes32 => ContributionRecord) private records;

    event ContributionRecorded(
        bytes32 indexed recordId,
        string trainingJobId,
        string participantDid,
        uint32 round,
        uint256 score
    );

    function recordContribution(
        string calldata trainingJobId,
        string calldata participantDid,
        uint32 round,
        uint256 score
    ) external returns (bytes32) {
        bytes32 recordId = keccak256(abi.encode(trainingJobId, participantDid, round));
        records[recordId] = ContributionRecord({
            trainingJobId: trainingJobId,
            participantDid: participantDid,
            round: round,
            score: score,
            recordedAt: uint64(block.timestamp)
        });

        emit ContributionRecorded(recordId, trainingJobId, participantDid, round, score);
        return recordId;
    }

    function getContribution(bytes32 recordId) external view returns (ContributionRecord memory) {
        return records[recordId];
    }
}

contracts/DataNotary.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

contract DataNotary {
    struct DataAsset {
        string datasetId;
        string ownerDid;
        string sm3Hash;
        string ipfsCid;
        uint64 registeredAt;
    }

    mapping(string => DataAsset) private assets;

    event DataRegistered(
        string indexed datasetId,
        string ownerDid,
        string sm3Hash,
        string ipfsCid,
        uint64 registeredAt
    );

    function registerDataAsset(
        string calldata datasetId,
        string calldata ownerDid,
        string calldata sm3Hash,
        string calldata ipfsCid
    ) external {
        require(bytes(datasetId).length > 0, "datasetId required");
        require(bytes(assets[datasetId].datasetId).length == 0, "dataset exists");

        DataAsset memory asset = DataAsset({
            datasetId: datasetId,
            ownerDid: ownerDid,
            sm3Hash: sm3Hash,
            ipfsCid: ipfsCid,
            registeredAt: uint64(block.timestamp)
        });

        assets[datasetId] = asset;
        emit DataRegistered(datasetId, ownerDid, sm3Hash, ipfsCid, asset.registeredAt);
    }

    function getDataAsset(string calldata datasetId) external view returns (DataAsset memory) {
        return assets[datasetId];
    }
}

contracts/DestroyManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

contract DestroyManager {
    struct DestroyProof {
        string datasetId;
        string operatorDid;
        string proofHash;
        uint64 destroyedAt;
    }

    mapping(string => DestroyProof) private proofs;

    event DataDestroyed(
        string indexed datasetId,
        string operatorDid,
        string proofHash,
        uint64 destroyedAt
    );

    function submitDestroyProof(
        string calldata datasetId,
        string calldata operatorDid,
        string calldata proofHash
    ) external {
        proofs[datasetId] = DestroyProof({
            datasetId: datasetId,
            operatorDid: operatorDid,
            proofHash: proofHash,
            destroyedAt: uint64(block.timestamp)
        });

        emit DataDestroyed(datasetId, operatorDid, proofHash, uint64(block.timestamp));
    }

    function getDestroyProof(string calldata datasetId) external view returns (DestroyProof memory) {
        return proofs[datasetId];
    }
}

contracts/DidRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

contract DidRegistry {
    struct DidDocumentRef {
        string did;
        string documentUri;
        bool active;
        uint64 updatedAt;
    }

    mapping(string => DidDocumentRef) private didDocuments;

    event DidDocumentUpdated(
        string indexed did,
        string documentUri,
        bool active,
        uint64 updatedAt
    );

    function upsertDidDocument(
        string calldata did,
        string calldata documentUri,
        bool active
    ) external {
        DidDocumentRef memory documentRef = DidDocumentRef({
            did: did,
            documentUri: documentUri,
            active: active,
            updatedAt: uint64(block.timestamp)
        });

        didDocuments[did] = documentRef;
        emit DidDocumentUpdated(did, documentUri, active, documentRef.updatedAt);
    }

    function getDidDocument(string calldata did) external view returns (DidDocumentRef memory) {
        return didDocuments[did];
    }
}

